+        /// <param name="tokenValues">The x-jwt-assertion header values.</param>
+        /// <returns>Result containing status, optional token payload, and optional error message.</returns>
+        public async Task<AgentForWebTokenExchangeResult> ExchangeAgentTokenForProjectSightToken(IEnumerable<string> tokenValues)
+        {
+            // Exceptions are handled in this method and returned as explicit HTTP status codes.
+
+            if (tokenValues == null)
+            {
+                return AgentForWebTokenExchangeResult.Failure(HttpStatusCode.Unauthorized, "Missing x-jwt-assertion header.");
+            }
+
+            var token = tokenValues.FirstOrDefault(value => !string.IsNullOrWhiteSpace(value));
+            if (string.IsNullOrWhiteSpace(token))
+            {
+                return AgentForWebTokenExchangeResult.Failure(HttpStatusCode.Unauthorized, "Missing x-jwt-assertion header.");
+            }
+
+            UserIdents idents;
+            try
+            {
+                idents = await TIDSupport.ExtractIdentityFromTokenAsync(token, true);
+            }
+            catch
+            {
+                return AgentForWebTokenExchangeResult.Failure(HttpStatusCode.Unauthorized, "Unauthorized.");
+            }
+
+            // User must have valid TID.
+            if (idents == null || idents.TrimbleID == Guid.Empty)
+            {
+                return AgentForWebTokenExchangeResult.Failure(HttpStatusCode.Unauthorized, "Unauthorized.");
+            }
+
+            // Since the JWT is a user token, its ClientID is null, so use Audience instead. If needed, we can check scope for ProjectSight-Agents.
+            if (!HasApprovedAudience(idents.Audiences))
+            {
+                return AgentForWebTokenExchangeResult.Failure(HttpStatusCode.Forbidden, "Forbidden.");
+            }
+
+            try
+                using (var ignitionDB = _dbHelperFactory.NewDBHelperIgnition())
+                    if (tokenResult == null || string.IsNullOrWhiteSpace(tokenResult.AccessToken))
+                    {
+                        return AgentForWebTokenExchangeResult.Failure(HttpStatusCode.Unauthorized, "Unauthorized.");
+                    }
+
+                    var response = new AgentForWebTokenExchangeResponse
+                    {
+                        ProjectSightToken = tokenResult.AccessToken,
+                        ExpiresAtUtc = tokenResult.ExpiresAt.UtcDateTime.ToString("yyyy-MM-ddTHH:mm:ssZ", CultureInfo.InvariantCulture)
+                    };
+
+                    return AgentForWebTokenExchangeResult.Success(response);
+                }
+            }
+            catch (Exception ex)
+            {
+                Logger.ReportErrorNoContext(ex);
+                return AgentForWebTokenExchangeResult.Failure(HttpStatusCode.InternalServerError, "Internal server error.");
+            }
+        }
+
+        private static bool HasApprovedAudience(List<Guid> audiences)
+        {
+            // Exceptions are handled by the caller.
+
+            if (audiences == null || audiences.Count == 0)
+            {
+                return false;
+            }
+
+            var service = Configuration.GetExternalService(ExternalService.Types.SecureTokenExchange);
+            var id = service?.EndPointID;
+            return !string.IsNullOrWhiteSpace(id)
+                && audiences.Any(audience => string.Equals(audience.ToString(), id, StringComparison.InvariantCultureIgnoreCase));
+        }
